/// <summary>
/// This is an data contract class for ETGDeliverySchedule report.
/// </summary>
[DataContractAttribute,SysOperationContractProcessing(classStr(ETGDeliveryReportUIBuilder))]
class ETGDeliveryScheduleReportContract implements SysOperationValidatable
{
    FromDate fromDate;
    ToDate toDate;
    str etgCommodity;
    str etgSubCommodity;
    //Container etgCommodityList; 
    //Container etgSubCommodityList;
    SalesId salesAgreementNumber;
    TransDate        salesAgreementDate;


}

Method.Source:
public void initialize()
{
    fromDate = dateNull();
    toDate   = dateNull();
    etgCommodity = '';
    etgSubCommodity = '';
    salesAgreementNumber  = '';
    salesAgreementDate    = dateNull();
}

/// <summary>
/// Gets and sets the value for data contract member FromDate
/// </summary>
/// <param name = "_fromDate">FromDate</param>
/// <returns>FromDate</returns>
[
    DataMemberAttribute('fromDate'),
    SysOperationLabelAttribute(literalStr("@ETG_New:FromDate"))
    //SysOperationHelpTextAttribute(literalStr("@ETG_New:FromDate"))
    //SysOperationGroupMemberAttribute('DateRange'),
    //SysOperationDisplayOrderAttribute('1')
]
public FromDate parmFromDate(FromDate _fromDate = fromDate)
{
    fromDate = _fromDate;
    return fromDate;
}

/// <summary>
/// Gets and sets the value for data contract member ToDate
/// </summary>
/// <param name = "_toDate">ToDate</param>
/// <returns>FromDate</returns>
[
    DataMemberAttribute('toDate'),
    SysOperationLabelAttribute(literalStr("toDate"))
    //SysOperationHelpTextAttribute(literalStr("To date"))
    //SysOperationGroupMemberAttribute('DateRange'),
    //SysOperationDisplayOrderAttribute('2')
]
public ToDate parmToDate(ToDate _toDate = toDate)
{
    toDate = _toDate;
    return toDate;
}

[
    DataMemberAttribute('etgCommodity'),
    SysOperationLabelAttribute(literalStr("etgCommodity"))
]
public str parmETGCommodity(str _etgCommodity = etgCommodity)
{
    etgCommodity = _etgCommodity;
    return etgCommodity;
}

[
    DataMemberAttribute('etgSubCommodity'),
    SysOperationLabelAttribute(literalStr("etgSubCommodity"))
]
public str parmETGSubCommodity(str _etgSubCommodity = etgSubCommodity)
{
    etgSubCommodity = _etgSubCommodity;
    return etgSubCommodity;
}

